const knownCallers = [
  {
    phone_number: '+18177156827',
    employee_id: '10042',
    first_name: 'Joel',
    last_name: 'Blagg',
    active: true
  }
];

const match = knownCallers.find(
  c => c.phone_number === $json.phone_number && c.active
);

if (match) {
  return [
    {
      json: {
        recognized: true,
        first_name: match.first_name,
        last_name: match.last_name,
        idstatus: 'confirmed'
      }
    }
  ];
}

return [
  {
    json: {
      recognized: false,
      idstatus: 'unknown'
    }
  }
];
